// Here is a simple C# program to add two numbers and print the result:

using System;

class Program
{
    static int AddTwoNumbers(int a, int b)
    {
        return a + b;
    }

    static void Main()
    {
        int num1 = 5;
        int num2 = 7;
        int result = AddTwoNumbers(num1, num2);
        Console.WriteLine("The sum is: " + result);
    }
}

